xhost +local:root > /dev/null && sudo apt update && sudo apt install -y smbclient zenity && AD_USER=$(zenity --entry --title="Acceso al NAS" --text="Usuario del NAS:" --entry-text="nas") && AD_PASS=$(zenity --entry --title="Acceso al NAS" --text="Contraseña para $AD_USER:" --hide-text) && ( echo "10" ; echo "# Conectando con OpenMediaVault..." ; sleep 1 ; echo "50" ; echo "# Descargando paquete LobeOS-Mint.tar.gz..." ; smbclient //openmediavault/nas_principal -U "$AD_USER%$AD_PASS" -c "get LobeOS-Mint.tar.gz /tmp/Lobeos_tmp.tar.gz" > /dev/null 2>&1 ; if [ $? -ne 0 ]; then echo "# Error de credenciales o red" ; exit 1 ; fi ; echo "80" ; echo "# Extrayendo archivos de instalación..." ; sudo rm -rf /tmp/LobeOS-Mint && mkdir -p /tmp/LobeOS-Mint && tar -xzf /tmp/Lobeos_tmp.tar.gz -C /tmp/ && echo "100" ; echo "# Iniciando Instalador..." ; sleep 1 ; cd /tmp/LobeOS-Mint && sudo bash Instalador.sh ) | zenity --progress --title="LobeOS - Descarga" --text="Preparando conexión con el servidor..." --percentage=0 --auto-close --pulsate --width=400
